package kyo.fixtures

/** JDK classfile bytes embedded for cross-platform tests.
  *
  * These are real JDK class file bytes extracted via `jimage extract` from $JAVA_HOME/lib/modules.
  * They are required by tests that pin specific JDK shapes (generics, NestHost/NestMembers,
  * PermittedSubclasses, MethodParameters, BootstrapMethods, throws clauses, annotations) and
  * cannot use synthetic classfiles without weakening those pins.
  *
  * Stored as Base64 strings decoded lazily on first access via `kyo.Base64.decodeOrThrow`. The
  * `kyo.Base64` variant is used (NOT `java.util.Base64`) because `java.util.Base64` is not
  * available on Scala Native; `kyo.Base64` is pure-Scala and cross-platform.
  *
  * Regeneration: extract the class bytes from $JAVA_HOME/lib/modules via `jimage extract`,
  * then encode via `kyo.Base64.encode(kyo.Span.fromUnsafe(bytes))`. Replace the relevant
  * Base64 string below and recompile.
  */
object EmbeddedClassfiles:

    /** Dispatch a JDK class binary path to its embedded byte array. */
    def loadJdkClass(binaryPath: String): Array[Byte] =
        binaryPath match
            case "java/util/ArrayList.class"                                 => javaUtilArrayListClass
            case "java/io/FileInputStream.class"                             => javaIoFileInputStreamClass
            case "java/util/function/Function.class"                         => javaUtilFunctionFunctionClass
            case "java/util/HashMap$Node.class"                              => javaUtilHashMapNodeClass
            case "java/util/HashMap.class"                                   => javaUtilHashMapClass
            case "java/lang/constant/ClassDesc.class"                        => javaLangConstantClassDescClass
            case "java/lang/module/ModuleDescriptor$Requires$Modifier.class" => javaLangModuleModuleDescriptorRequiresModifierClass
            case "java/lang/Deprecated.class"                                => javaLangDeprecatedClass
            case other =>
                throw new RuntimeException(
                    s"EmbeddedClassfiles.loadJdkClass: no embedded class for '$other'; add it to EmbeddedClassfiles.scala"
                )
    end loadJdkClass

    /** Contents of `java/util/ArrayList.class` (19356 bytes). */
    private lazy val javaUtilArrayListClassData: Array[Byte] =
        kyo.Base64.decodeOrThrow(
            ""
        ).toArrayUnsafe
    def javaUtilArrayListClass: Array[Byte] = javaUtilArrayListClassData

    /** Contents of `java/io/FileInputStream.class` (7555 bytes). */
    private lazy val javaIoFileInputStreamClassData: Array[Byte] =
        kyo.Base64.decodeOrThrow(
            ""
        ).toArrayUnsafe
    def javaIoFileInputStreamClass: Array[Byte] = javaIoFileInputStreamClassData

    /** Contents of `java/util/function/Function.class` (2392 bytes). */
    private lazy val javaUtilFunctionFunctionClassData: Array[Byte] =
        kyo.Base64.decodeOrThrow(
            ""
        ).toArrayUnsafe
    def javaUtilFunctionFunctionClass: Array[Byte] = javaUtilFunctionFunctionClassData

    /** Contents of `java/util/HashMap$Node.class` (2316 bytes). */
    private lazy val javaUtilHashMapNodeClassData: Array[Byte] =
        kyo.Base64.decodeOrThrow(
            ""
        ).toArrayUnsafe
    def javaUtilHashMapNodeClass: Array[Byte] = javaUtilHashMapNodeClassData

    /** Contents of `java/util/HashMap.class` (26411 bytes). */
    private lazy val javaUtilHashMapClassData: Array[Byte] =
        kyo.Base64.decodeOrThrow(
            ""
        ).toArrayUnsafe
    def javaUtilHashMapClass: Array[Byte] = javaUtilHashMapClassData

    /** Contents of `java/lang/constant/ClassDesc.class` (3879 bytes). */
    private lazy val javaLangConstantClassDescClassData: Array[Byte] =
        kyo.Base64.decodeOrThrow(
            ""
        ).toArrayUnsafe
    def javaLangConstantClassDescClass: Array[Byte] = javaLangConstantClassDescClassData

    /** Contents of `java/lang/module/ModuleDescriptor$Requires$Modifier.class` (1835 bytes). */
    private lazy val javaLangModuleModuleDescriptorRequiresModifierClassData: Array[Byte] =
        kyo.Base64.decodeOrThrow(
            ""
        ).toArrayUnsafe
    def javaLangModuleModuleDescriptorRequiresModifierClass: Array[Byte] = javaLangModuleModuleDescriptorRequiresModifierClassData

    /** Contents of `java/lang/Deprecated.class` (647 bytes). */
    private lazy val javaLangDeprecatedClassData: Array[Byte] =
        kyo.Base64.decodeOrThrow(
            ""
        ).toArrayUnsafe
    def javaLangDeprecatedClass: Array[Byte] = javaLangDeprecatedClassData

end EmbeddedClassfiles
